const express = require('express');
const jwt = require('jsonwebtoken');
const session = require('express-session');
const axios = require('axios');

const app = express();
app.use(express.json());
app.use(session({ secret: 'your-secret-key', resave: false, saveUninitialized: true }));

const openIDProvider = 'https://your-openid-provider.com';
const clientID = 'your-client-id';
const redirectURI = 'http://localhost:3000/callback';

app.get('/login', (req, res) => {
    const authURL = `${openIDProvider}/authorize?response_type=id_token&client_id=${clientID}&redirect_uri=${redirectURI}&scope=openid profile`;
    res.redirect(authURL);
});

app.get('/callback', async (req, res) => {
    const idToken = req.query.id_token;

    if (idToken) {
        const decodedToken = jwt.decode(idToken);
        req.session.user = {
            sub: decodedToken.sub,
            name: decodedToken.name,
            email: decodedToken.email,
            // Add other claims as necessary
        };
        res.redirect('/profile');
    } else {
        res.status(400).send('No ID token received');
    }
});

app.get('/profile', (req, res) => {
    if (req.session.user) {
        res.json(req.session.user);
    } else {
        res.status(401).send('Unauthorized');
    }
});

app.listen(3000, () => {
    console.log('Server is running on http://localhost:3000');
});